import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        int[] nums = {0, 1, 0, 3, 12};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{1, 3, 12, 0, 0}, nums);
    }

    @Test
    void noZeros() {
        int[] nums = {1, 2, 3};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{1, 2, 3}, nums);
    }

    @Test
    void allZeros() {
        int[] nums = {0, 0, 0};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{0, 0, 0}, nums);
    }

    @Test
    void single() {
        int[] nums = {0};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{0}, nums);
    }

    @Test
    void empty() {
        int[] nums = {};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{}, nums);
    }

    @Test
    void leadingNonZero() {
        // zeros interspersed, first element is non-zero
        int[] nums = {1, 0, 2, 0, 3, 0};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{1, 2, 3, 0, 0, 0}, nums);
    }

    @Test
    void alternatingStartZero() {
        // adversarial: strictly alternating, starts with zero
        int[] nums = {0, 1, 0, 1, 0, 1};
        new Solution().moveZeros(nums);
        assertArrayEquals(new int[]{1, 1, 1, 0, 0, 0}, nums);
    }
}
